import urllib.request
import json

# Try Wikipedia API for Macau history in English
try:
    url = "https://en.wikipedia.org/w/api.php?action=query&titles=History_of_Macau&prop=extracts&explaintext&format=json&redirects=1"
    req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0 (Macintosh; Intel Mac OS X 10_15_7)'})
    resp = urllib.request.urlopen(req, timeout=10)
    data = json.loads(resp.read())
    pages = data.get('query', {}).get('pages', {})
    for page_id, page in pages.items():
        if 'extract' in page:
            extract = page['extract']
            # Find 1553 mentions
            for kw in ['1553', '1557', 'Portuguese', 'landing']:
                idx = extract.find(kw)
                if idx >= 0:
                    print(f"=== Found '{kw}' ===")
                    print(extract[max(0,idx-100):idx+400])
                    print()
except Exception as e:
